## 3. ChatMessage 엔티티 구조 (예상)

기존 프로젝트 컨벤션을 따를 경우:

```kotlin
// domain/src/main/kotlin/com/maum/backend/entity/chat/ChatMessageEntity.kt
@Entity
@Table(catalog = "chat", name = "chat_message")
class ChatMessageEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "chat_room_id")
    val chatRoom: ChatRoomEntity? = null,

    val senderId: String,  // gRPC/GraphQL 호출로 채워짐

    @Column(columnDefinition = "longtext")
    var content: String?,  // 텍스트 메시지

    var messageType: Int = 0,  // Enum: TEXT(0), IMAGE(1), VOICE(2), etc.

    var status: Int = 0,  // Enum: SENT(0), DELIVERED(1), READ(2), DELETED(3)

    // 이미지 관련 필드
    @OneToMany(mappedBy = "chatMessage", fetch = FetchType.LAZY)
    val mediaFiles: List<ChatMediaFileEntity> = emptyList(),

    var imageUrl: String? = null,  // S3 URL 또는 CDN URL
    var imageMeta: String? = null,  // JSON: {width, height, size, mimeType}

    // 감사 필드
    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),

    var deletedAt: LocalDateTime? = null,  // 소프트 삭제
)

// 메시지 타입 Enum
enum class MessageType(val value: Int) {
    TEXT(0),
    IMAGE(1),
    VOICE(2),
    VIDEO(3),
    FILE(4);

    companion object {
        fun fromValue(value: Int) = entries.first { it.value == value }
    }
}

// 메시지 상태 Enum
enum class MessageStatus(val value: Int) {
    SENT(0),
    DELIVERED(1),
    READ(2),
    DELETED(3);

    companion object {
        fun fromValue(value: Int) = entries.first { it.value == value }
    }
}
```

