## 5. chat.proto 파일 (예상 구조)

```protobuf
syntax = "proto3";
package chat;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.chat";

service ChatService {
    rpc GetChatRoom(GetChatRoomRequest) returns (GetChatRoomResponse);
    rpc ListMessages(ListMessagesRequest) returns (ListMessagesResponse);
    rpc SendMessage(SendMessageRequest) returns (SendMessageResponse);
    rpc SendImageMessage(SendImageMessageRequest) returns (SendImageMessageResponse);
    rpc UpdateMessageStatus(UpdateMessageStatusRequest) returns (UpdateMessageStatusResponse);
    rpc DeleteMessage(DeleteMessageRequest) returns (DeleteMessageResponse);
}

message GetChatRoomRequest {
    string chat_room_id = 1;
    string user_id = 2;
}

message GetChatRoomResponse {
    ChatRoom chat_room = 1;
}

message ChatRoom {
    string id = 1;
    string user_id_1 = 2;
    string user_id_2 = 3;
    int64 created_at = 4;
    int64 updated_at = 5;
}

message ListMessagesRequest {
    string chat_room_id = 1;
    int32 limit = 2;
    int32 offset = 3;
}

message ListMessagesResponse {
    repeated ChatMessage messages = 1;
}

message ChatMessage {
    string id = 1;
    string chat_room_id = 2;
    string sender_id = 3;
    string content = 4;
    int32 message_type = 5;  // 0: TEXT, 1: IMAGE, 2: VOICE, etc.
    int32 status = 6;        // 0: SENT, 1: DELIVERED, 2: READ
    repeated MediaFile media_files = 7;
    int64 created_at = 8;
}

message MediaFile {
    string id = 1;
    string file_type = 2;  // "image", "video", "audio"
    string mime_type = 3;  // "image/jpeg", "image/png"
    string file_url = 4;
    string file_name = 5;
    int64 file_size = 6;
    int32 width = 7;
    int32 height = 8;
    string thumbnail_url = 9;
}

message SendMessageRequest {
    string chat_room_id = 1;
    string sender_id = 2;
    string content = 3;
}

message SendMessageResponse {
    ChatMessage message = 1;
}

message SendImageMessageRequest {
    string chat_room_id = 1;
    string sender_id = 2;
    string image_url = 3;  // S3 URL (사전 업로드됨)
    int32 width = 4;
    int32 height = 5;
    string mime_type = 6;  // "image/jpeg"
}

message SendImageMessageResponse {
    ChatMessage message = 1;
}

message UpdateMessageStatusRequest {
    string message_id = 1;
    int32 status = 2;  // 1: DELIVERED, 2: READ
}

message UpdateMessageStatusResponse {
    ChatMessage message = 1;
}

message DeleteMessageRequest {
    string message_id = 1;
    string user_id = 2;
}

message DeleteMessageResponse {
    bool success = 1;
}
```

