## 6. GraphQL 스키마 (chat.graphqls)

```graphql
type ChatMessage {
    id: ID!
    chatRoom: ChatRoom!
    sender: SimpleUser!
    content: String
    messageType: MessageType!
    status: MessageStatus!
    mediaFiles: [MediaFile!]!
    createdAt: String!
    updatedAt: String!
}

type MediaFile {
    id: ID!
    fileType: String!
    mimeType: String!
    fileUrl: String!
    fileName: String!
    fileSize: Int!
    width: Int
    height: Int
    thumbnailUrl: String
}

type ChatRoom {
    id: ID!
    participants: [ChatParticipant!]!
    lastMessage: ChatMessage
    unreadCount: Int!
    createdAt: String!
}

type ChatParticipant {
    id: ID!
    user: SimpleUser!
    joinedAt: String!
}

enum MessageType {
    TEXT
    IMAGE
    VOICE
    VIDEO
    FILE
}

enum MessageStatus {
    SENT
    DELIVERED
    READ
    DELETED
}

input SendMessageInput {
    chatRoomId: ID!
    content: String!
}

input SendImageMessageInput {
    chatRoomId: ID!
    imageUrl: String!  # S3 사전 업로드
    width: Int!
    height: Int!
    mimeType: String!
}

input CreatePresignedUrlInput {
    fileName: String!
    mimeType: String!
    fileSize: Int!
}

type PresignedUrl {
    uploadUrl: String!
    downloadUrl: String!
    expireAt: String!
}

extend type Query {
    chatRoom(roomId: ID!): ChatRoom
    messages(
        roomId: ID!
        limit: Int = 20
        offset: Int = 0
    ): [ChatMessage!]!
}

extend type Mutation {
    sendMessage(input: SendMessageInput!): ChatMessage!
    sendImageMessage(input: SendImageMessageInput!): ChatMessage!
    createPresignedUrl(input: CreatePresignedUrlInput!): PresignedUrl!
    updateMessageStatus(messageId: ID!, status: MessageStatus!): ChatMessage!
    deleteMessage(messageId: ID!): Boolean!
}
```

