## 7. GraphQL Controller 메서드 시그니처

```kotlin
@Controller
class ChatController(
    private val chatService: ChatService,
    private val mediaUploadService: MediaUploadService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun chatRoom(
        @UserId userId: String,
        @Argument roomId: String,
    ): ChatRoomResponse {
        return chatService.getChatRoom(userId, roomId)
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun messages(
        @UserId userId: String,
        @Argument roomId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): List<ChatMessageResponse> {
        return chatService.listMessages(userId, roomId, limit ?: 20, offset ?: 0)
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun sendMessage(
        @UserId userId: String,
        @Argument input: SendMessageInput,
    ): ChatMessageResponse {
        return chatService.sendMessage(userId, input)
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun sendImageMessage(
        @UserId userId: String,
        @Argument input: SendImageMessageInput,
    ): ChatMessageResponse {
        return chatService.sendImageMessage(userId, input)
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun createPresignedUrl(
        @UserId userId: String,
        @Argument input: CreatePresignedUrlInput,
    ): PresignedUrlResponse {
        return mediaUploadService.generatePresignedUrl(userId, input)
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateMessageStatus(
        @UserId userId: String,
        @Argument messageId: String,
        @Argument status: String,
    ): ChatMessageResponse {
        return chatService.updateMessageStatus(userId, messageId, status)
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun deleteMessage(
        @UserId userId: String,
        @Argument messageId: String,
    ): Boolean {
        return chatService.deleteMessage(userId, messageId)
    }
}
```

